import os, re, glob
from PIL import Image
import pytesseract

FRAMES_DIR='/tmp/zork_frames_5fps'
MOVES_RE=re.compile(r'Moves?\s*:?\s*(\d+)', re.I)

def find_frames():
    dirs=[FRAMES_DIR, '/tmp/zork_frames_5fps_clean', '/tmp/zork_final_frames']
    for d in dirs:
        if os.path.isdir(d):
            frames=sorted(glob.glob(os.path.join(d,'*.png')))
            if len(frames) > 100:
                print('using frames', d, len(frames))
                return frames
    print('no frames found')
    return None

frames=find_frames()
if not frames:
    raise SystemExit(1)

def ocr_box(im, box, psm):
    crop=im.convert('L').crop(box)
    crop=crop.resize((crop.width*3, crop.height*3))
    bw=crop.point(lambda x: 0 if x < 150 else 255, '1')
    return pytesseract.image_to_string(bw, config=f'--psm {psm}')

def get_moves(im):
    w,h=im.size
    for frac in (0.07, 0.09, 0.12):
        txt=ocr_box(im, (0,0,w,int(h*frac)), 7)
        m=MOVES_RE.search(txt)
        if m:
            return int(m.group(1))
    return None

def clean_lines(txt):
    out=[]
    for s in txt.splitlines():
        s=s.encode('ascii',errors='ignore').decode()
        s=s.replace('>',' ').replace('_','').replace('|','')
        s=re.sub(r'\s+',' ',s).strip()
        if s:
            out.append(s)
    return out

def is_game_output(low):
    phrases=[
        'done','taken','you are','you hear','you see','there is','there are',
        'on the ground','suspicious','stiletto','scream','butt','this is','it is',
        'can be seen','strange passage','cyclops room','slide room','mine entrance',
        'squeaky room','white cliffs','damp cave','loud room','treasure room',
        'jewel','platinum','silver chalice','thief','deflates','your own feet',
        'heavy iron','chain','three sides','at the end','room score','moves',
        'revision','serial','copyright','zork','infocom','all rights','west of house',
        'staircase','reservoir','southeast','more'
    ]
    return any(p in low for p in phrases)

verbs={'get','take','drop','put','open','close','light','kill','slay','move','push','pull',
       'set','raise','lower','wave','dig','shove','give','wind','pray','save','look',
       'inventory','read','rub','climb','pour','fill','blow','throw','attack','drink',
       'eat','count','wait','board','disembark','launch','land','unwrap','tie','untie',
       'turn','press','type','enter','go','examine','lock','unlock','inflate','deflate',
       'pump','squeeze','touch','kick','jump','swim','cross','leave','follow','shoot',
       'solve','ring'}

def looks_move(s):
    low=s.lower().strip()
    if not low or is_game_output(low):
        return False
    if low in {'n','s','e','w','u','d','ne','nw','se','sw'}:
        return True
    if len(low) > 60 or re.search(r'\d{4,}', low):
        return False
    parts=low.split()
    if not parts:
        return False
    if parts[0] not in verbs:
        return False
    return bool(re.fullmatch(r'[a-z0-9 ,.\-]{1,60}', low))

states=[]
for idx,p in enumerate(frames):
    t=idx/5.0
    im=Image.open(p)
    w,h=im.size
    mv=get_moves(im)
    ptxt=ocr_box(im, (0,int(h*0.82),w,h), 7)
    lines=clean_lines(ptxt)
    cmd=lines[-1] if lines else ''
    states.append((t,mv,cmd))

detected=[]
final=[]
prev_mv=None
cur=''
for t,mv,cmd in states:
    if mv is not None and prev_mv is not None and mv > prev_mv:
        c=cur.strip()
        if looks_move(c):
            final.append((t, c))
        cur=''
    elif cmd and cmd != cur:
        cur=cmd
    if mv is not None:
        prev_mv=mv

cleaned=[]
for t,c in final:
    cl=c.strip().rstrip('.')
    if not cl:
        continue
    if cleaned and cleaned[-1].lower() == cl.lower():
        continue
    cleaned.append((t, cl))

with open('/app/solution.txt','w') as f:
    for t,c in cleaned:
        f.write(c+'\n')

print('detected raw move events', len(final))
print('final moves', len(cleaned))
for i,(t,c) in enumerate(cleaned,1):
    print(f'{i:3d} {t:6.1f} {c}')
PY
